12	macro_rules! define_ptx_asm_out {
13	    ($name:ident; $($arg:ident : $ty:ident),*) => {
14	        #[doc(hidden)]
15	        #[inline(never)]
16	        #[allow(unused_variables)]
17	        #[allow(clippy::too_many_arguments)]
18	        /// # Safety
19	        ///
20	        /// Compiler marker for `ptx_asm!`; user code must not call this directly.
21	        pub unsafe fn $name<
22	            T,
23	            const TEMPLATE_LEN: usize,
24	            const CONSTRAINTS_LEN: usize,
25	            const OPTIONS_LEN: usize,
26	            $($ty,)*
27	        >(
