1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! End-to-end test for `cp.async` zero-fill intrinsics.
7	//!
8	//! Demonstrates asynchronous global-to-shared memory copies with
9	//! hardware zero-fill using the `src_size` parameter. When
10	//! `src_size < cp_size`, the remaining bytes are zero-filled.
11	//!
12	//! Tests the 4-byte variant by copying 2 of 4 bytes and verifying the
13	//! upper 2 bytes are zeroed.
14	//!
15	//! Requires **sm_80+** (Ampere or later).
16	//!
17	//! Build and run with:
18	//!   cargo oxide run cp_async_zfill
19	
20	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
21	use cuda_device::async_copy::cp_async_ca_zfill_4;
22	use cuda_device::{DisjointSlice, SharedArray, cuda_module, kernel, ptx_asm, thread};
23	
24	// =============================================================================
25	// KERNELS
26	// =============================================================================
27	
28	#[cuda_module]
29	mod kernels {
30	    use super::*;
31	
32	    /// Each thread copies `src_size` bytes (out of 4) from global to shared
33	    /// memory via `cp.async.ca.shared.global [...], [...], 4, src_size;`.
34	    /// The remaining `4 - src_size` bytes are zero-filled by hardware.
35	    #[kernel]
36	    pub fn test_zfill_4(input: &[u32], src_size: u32, mut out: DisjointSlice<u32>) {
37	        static mut SMEM: SharedArray<u32, 32> = SharedArray::UNINIT;
38	
39	        let tid = thread::threadIdx_x() as usize;
40	        let gid = thread::index_1d();
41	        let dst_ptr = unsafe { (core::ptr::addr_of_mut!(SMEM) as *mut u32).add(tid) };
42	
43	        // Pre-fill shared memory with a sentinel so we can detect zero-fill.
44	        unsafe {
45	            dst_ptr.write(0xDEAD_BEEF);
46	        }
47	        thread::sync_threads();
48	
49	        let src_ptr = unsafe { input.as_ptr().add(gid.get()) as *const u8 };
50	
51	        // Initiate the zero-fill copy, commit, and wait.
52	        unsafe {
53	            cp_async_ca_zfill_4(dst_ptr, src_ptr, src_size);
54	            ptx_asm!("cp.async.commit_group;", clobber("memory"));
55	            ptx_asm!("cp.async.wait_all;", clobber("memory"));
56	        }
57	
58	        thread::sync_threads();
59	
60	        let val = unsafe { dst_ptr.read() };
61	        if let Some(slot) = out.get_mut(gid) {
62	            *slot = val;
63	        }
64	    }
65	}
66	
67	// =============================================================================
68	// HOST CODE
69	// =============================================================================
70	
71	fn main() {
72	    println!("=== cp.async zero-fill example ===\n");
73	
74	    let ctx = CudaContext::new(0).expect("Failed to create CUDA context");
75	
76	    let (major, minor) = ctx.compute_capability().expect("compute capability");
77	    if major < 8 {
78	        println!(
79	            "Skipping: cp.async requires sm_80+, device is sm_{}{} -- PASS (skipped)",
80	            major, minor
81	        );
82	        return;
83	    }
84	
85	    let stream = ctx.default_stream();
86	    let module = kernels::load(&ctx).expect("Failed to load embedded CUDA module");
87	
88	    let cfg = LaunchConfig {
89	        grid_dim: (1, 1, 1),
90	        block_dim: (32, 1, 1),
91	        shared_mem_bytes: 0,
92	    };
93	
94	    let mut all_pass = true;
95	
96	    // ----- Test 1: full copy (src_size == 4), no zero-fill -----
97	    println!("--- Test 1: src_size=4 (full copy, no zero-fill) ---");
98	    {
99	        let input: Vec<u32> = (0xAAAA_0000..0xAAAA_0020).collect();
100	        let input_dev = DeviceBuffer::from_host(&stream, &input).unwrap();
101	        let mut out_dev = DeviceBuffer::<u32>::zeroed(&stream, 32).unwrap();
102	
103	        // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
104	        unsafe { module.test_zfill_4(&stream, cfg, &input_dev, 4u32, &mut out_dev) }
105	            .expect("launch failed");
106	
107	        let mut test_pass = true;
108	        let out = out_dev.to_host_vec(&stream).unwrap();
109	        for i in 0..32 {
110	            if out[i] != input[i] {
111	                eprintln!(
112	                    "  FAIL [{}]: expected 0x{:08X}, got 0x{:08X}",
113	                    i, input[i], out[i]
114	                );
115	                test_pass = false;
116	                all_pass = false;
117	            }
118	        }
119	        if test_pass {
120	            println!("  PASS: 32 elements copied with src_size=4");
121	        }
122	    }
123	
124	    // ----- Test 2: partial copy (src_size == 2), upper 2 bytes zeroed -----
125	    println!("--- Test 2: src_size=2 (partial copy, upper bytes zeroed) ---");
126	    {
127	        // Input: each element is 0xAABBCCDD.
128	        // With src_size=2 on little-endian, bytes 0-1 (0xDD, 0xCC) are copied,
129	        // bytes 2-3 are zero-filled, giving 0x0000CCDD.
130	        let input: Vec<u32> = vec![0xAABBCCDD; 32];
131	        let input_dev = DeviceBuffer::from_host(&stream, &input).unwrap();
132	        let mut out_dev = DeviceBuffer::<u32>::zeroed(&stream, 32).unwrap();
133	
134	        // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
135	        unsafe { module.test_zfill_4(&stream, cfg, &input_dev, 2u32, &mut out_dev) }
136	            .expect("launch failed");
137	
138	        let mut test_pass = true;
139	        let out = out_dev.to_host_vec(&stream).unwrap();
140	        let expected = 0x0000_CCDD_u32;
141	        for (i, &actual) in out.iter().enumerate() {
142	            if actual != expected {
143	                eprintln!(
144	                    "  FAIL [{}]: expected 0x{:08X}, got 0x{:08X}",
145	                    i, expected, actual
146	                );
147	                test_pass = false;
148	                all_pass = false;
149	            }
150	        }
151	        if test_pass {
152	            println!("  PASS: upper 2 bytes zeroed with src_size=2");
153	        }
154	    }
155	
156	    // ----- Test 3: zero copy (src_size == 0), entire word zeroed -----
157	    println!("--- Test 3: src_size=0 (zero copy, entire word zeroed) ---");
158	    {
159	        let input: Vec<u32> = vec![0xFFFF_FFFF; 32];
160	        let input_dev = DeviceBuffer::from_host(&stream, &input).unwrap();
161	        let mut out_dev = DeviceBuffer::<u32>::zeroed(&stream, 32).unwrap();
162	
163	        // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
164	        unsafe { module.test_zfill_4(&stream, cfg, &input_dev, 0u32, &mut out_dev) }
165	            .expect("launch failed");
166	
167	        let mut test_pass = true;
168	        let out = out_dev.to_host_vec(&stream).unwrap();
169	        for (i, &actual) in out.iter().enumerate() {
170	            if actual != 0 {
171	                eprintln!("  FAIL [{i}]: expected 0x00000000, got 0x{actual:08X}");
172	                test_pass = false;
173	                all_pass = false;
174	            }
175	        }
176	        if test_pass {
177	            println!("  PASS: entire word zeroed with src_size=0");
178	        }
179	    }
180	
181	    if !all_pass {
182	        println!("\nFAIL: cp.async zero-fill, one or more checks failed");
183	        std::process::exit(1);
184	    }
